lessons.example:
def shout(func):
    def wrapper():
        print('>>>')
        func()
        print('<<<')
    return wrapper

@shout
def hi():
    print('Привет')

hi()

def count_up(n):
    for i in range(n):
        yield i

for x in count_up(3):
    print(x)

